CREATE DATABASE IF NOT EXISTS bv_assist_campus_connect; USE bv_assist_campus_connect; CREATE TABLE users (user_id INT PRIMARY KEY AUTO_INCREMENT, email VARCHAR(255) UNIQUE NOT NULL, password VARCHAR(255) NOT NULL, role ENUM('Student','Faculty','Admin') NOT NULL, created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP, INDEX(email), INDEX(role)); CREATE TABLE faculty_uploads (id INT PRIMARY KEY AUTO_INCREMENT, title VARCHAR(255) NOT NULL, file_name VARCHAR(255) NOT NULL, uploaded_by VARCHAR(255) NOT NULL, uploaded_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP, FOREIGN KEY (uploaded_by) REFERENCES users(email) ON DELETE CASCADE, INDEX(uploaded_by), INDEX(uploaded_at)); CREATE TABLE notifications (id INT PRIMARY KEY AUTO_INCREMENT, title VARCHAR(255) NOT NULL, message TEXT NOT NULL, created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP, posted_by VARCHAR(255), INDEX(created_at)); CREATE TABLE feedback (id INT PRIMARY KEY AUTO_INCREMENT, student_email VARCHAR(255) NOT NULL, message TEXT NOT NULL, created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP, FOREIGN KEY (student_email) REFERENCES users(email) ON DELETE CASCADE, INDEX(student_email), INDEX(created_at)); CREATE TABLE activity_log (id INT PRIMARY KEY AUTO_INCREMENT, action VARCHAR(255) NOT NULL, user_email VARCHAR(255), timestamp TIMESTAMP DEFAULT CURRENT_TIMESTAMP, INDEX(user_email), INDEX(timestamp)); INSERT INTO users (email, password, role) VALUES ('student@college.com', '$2y$10$7qpJsN5QZF7QJ5K5K5K5K5rL0mN1vV2hJ0Wq9pS3rL4xY6Z9a8B9C', 'Student'), ('faculty@college.com', '$2y$10$7qpJsN5QZF7QJ5K5K5K5K5rL0mN1vV2hJ0Wq9pS3rL4xY6Z9a8B9C', 'Faculty'), ('admin@college.com', '$2y$10$7qpJsN5QZF7QJ5K5K5K5K5rL0mN1vV2hJ0Wq9pS3rL4xY6Z9a8B9C', 'Admin'); INSERT INTO notifications (title, message, posted_by) VALUES ('Welcome to BV Assist', 'Welcome to Campus Connect system', 'admin@college.com'), ('System Notice', 'System maintenance on Sunday', 'admin@college.com'); COMMIT;